// Input: Encoded bit string and Huffman tree root
// Output: Original message

DECODE(encodedBits, root):
 currentNode = root
 output = ""

 for each bit in encodedBits:
 if bit == '0':
 currentNode = currentNode.left
 else: // bit == '1'
 currentNode = currentNode.right

 // Check if leaf node reached
 if currentNode is leaf:
 output += currentNode.character
 currentNode = root // Reset to root

 return output

