// Problem: Merge n files with sizes s1, s2, ..., sn
// Goal: Minimize total merge cost

OPTIMAL-MERGE(files):
 // Create min-heap of all file sizes
 Q = PRIORITY-QUEUE()

 for each file size in files:
 Q.INSERT(file size)

 totalCost = 0

 // While more than one file remains
 while Q.SIZE() > 1:
 // Extract two smallest files
 file1 = Q.EXTRACT-MIN()
 file2 = Q.EXTRACT-MIN()

 // Merge cost = sum of both file sizes
 mergedCost = file1 + file2
 totalCost += mergedCost

 // Insert merged file back
 Q.INSERT(mergedCost)

 return totalCost

// Example:
// Files: [20, 15, 10, 5, 25]
// Step 1: Merge 5+10=15, cost=15, Q=[15,15,20,25]
// Step 2: Merge 15+15=30, cost=30, Q=[20,25,30]
